from flask import Flask, redirect, url_for, request
import requests

app = Flask(__name__)

# Client configuration
client_id = 'your_client_id'
client_secret = 'your_client_secret'

# Authorization endpoint URL
authorization_endpoint_url = 'https://example.com/oauth/authorize'

# Token endpoint URL
token_endpoint_url = 'https://example.com/oauth/token'

# Redirect URI from client configuration
redirect_uri = 'http://localhost:5000/callback'

# Domain for validation
domain = 'your_domain.com'

@app.route('/login')
def login():
    # Construct authorization request URL
    auth_request_url = f'{authorization_endpoint_url}?'
    auth_request_url += f'client_id={client_id}&'
    auth_request_url += f'redirect_uri={redirect_uri}&'
    auth_request_url += 'response_type=code&'
    auth_request_url += 'scope=read'

    # Check if redirect URI matches the configured domain
    if domain in redirect_uri:
        return redirect(auth_request_url)
    else:
        return 'Invalid redirect URI', 400

@app.route('/callback')
def callback():
    code = request.args.get('code')
    # Exchange authorization code for access token
    token_response = requests.post(
        token_endpoint_url,
        headers={'Content-Type': 'application/x-www-form-urlencoded'},
        data={
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': redirect_uri,
            'client_id': client_id,
            'client_secret': client_secret
        }
    )
    # Handle token response
    return token_response.text

if __name__ == '__main__':
    app.run(debug=True)